"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[33574],{11669:(e,t,i)=>{i.r(t),i.d(t,{assets:()=>l,contentTitle:()=>o,default:()=>h,frontMatter:()=>s,metadata:()=>a,toc:()=>d});const a=JSON.parse('{"id":"Preface End facism/eos/EO_14362_DTerrorists_gpt-5_4_20260307_005058","title":"EO 14362 Designation of Certain Muslim Brotherhood Chapters as Foreign Terrorist Organizations and Specially Designated Global Terrorists","description":"Table of Contents","source":"@site/docs/1. Preface End facism/eos/EO_14362_DTerrorists_gpt-5_4_20260307_005058.md","sourceDirName":"1. Preface End facism/eos","slug":"/Preface End facism/eos/EO_14362_DTerrorists_gpt-5_4_20260307_005058","permalink":"/firstpub-Platform/docs/Preface End facism/eos/EO_14362_DTerrorists_gpt-5_4_20260307_005058","draft":false,"unlisted":false,"editUrl":"https://github.com/unitedprogressparty/firstpub-Platform/tree/main/docs/1. Preface End facism/eos/EO_14362_DTerrorists_gpt-5_4_20260307_005058.md","tags":[],"version":"current","frontMatter":{"title":"EO 14362 Designation of Certain Muslim Brotherhood Chapters as Foreign Terrorist Organizations and Specially Designated Global Terrorists"},"sidebar":"tutorialSidebar","previous":{"title":"EO 14299 Deploying Advanced Nuclear Reactor Technologies for National Security","permalink":"/firstpub-Platform/docs/Preface End facism/eos/EO_14299_Dl_Security_gpt-5_4_20260307_005056"},"next":{"title":"EO 14369 Ensuring American Space Superiority","permalink":"/firstpub-Platform/docs/Preface End facism/eos/EO_14369_Euperiority_gpt-5-mini_20260306_120150"}}');var n=i(74848),r=i(28453);const s={title:"EO 14362 Designation of Certain Muslim Brotherhood Chapters as Foreign Terrorist Organizations and Specially Designated Global Terrorists"},o="EO 14362: Designation of Certain Muslim Brotherhood Chapters as Foreign Terrorist Organizations and Specially Designated Global Terrorists",l={},d=[{value:"Table of Contents",id:"table-of-contents",level:2},{value:"Executive Summary",id:"executive-summary",level:2},{value:"What the Order Formally Says, and What It Really Does",id:"what-the-order-formally-says-and-what-it-really-does",level:2},{value:"How the Order Was Implemented",id:"how-the-order-was-implemented",level:2},{value:"Who the Administration Is Trying to Hurt",id:"who-the-administration-is-trying-to-hurt",level:2},{value:"Legal Authority, Constitutional Stakes, and Oversight",id:"legal-authority-constitutional-stakes-and-oversight",level:2},{value:"Durability, Litigation Exposure, and How a Later Administration Could Reverse It",id:"durability-litigation-exposure-and-how-a-later-administration-could-reverse-it",level:2},{value:"Implementation Feasibility, Agency Capacity, and Procedural Requirements",id:"implementation-feasibility-agency-capacity-and-procedural-requirements",level:2},{value:"Fiscal and Economic Effects",id:"fiscal-and-economic-effects",level:2},{value:"Downstream Developments and Broader Governing Pattern",id:"downstream-developments-and-broader-governing-pattern",level:2},{value:"Harms, Risks, and Second-Order Effects",id:"harms-risks-and-second-order-effects",level:2},{value:"Corruption and Self-Dealing Risk",id:"corruption-and-self-dealing-risk",level:2},{value:"Final Assessment",id:"final-assessment",level:2}];function c(e){const t={a:"a",h1:"h1",h2:"h2",header:"header",p:"p",...(0,r.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"eo-14362-designation-of-certain-muslim-brotherhood-chapters-as-foreign-terrorist-organizations-and-specially-designated-global-terrorists",children:"EO 14362: Designation of Certain Muslim Brotherhood Chapters as Foreign Terrorist Organizations and Specially Designated Global Terrorists"})}),"\n",(0,n.jsx)(t.h2,{id:"table-of-contents",children:"Table of Contents"}),"\n",(0,n.jsxs)(t.p,{children:["This report begins by establishing what Executive Order 14362 formally did and did not do, then explains how the order actually functioned in practice once the administration operationalized it in January 2026. It then examines who was targeted, who benefits, who bears the costs, and why the order should be understood as part of a broader governing style that converts terrorism authorities into instruments of ideological policing and alliance management. It next assesses legal authority, institutional and constitutional implications, durability, litigation exposure, implementation feasibility, agency capacity, fiscal and economic effects, downstream developments, concrete harms and risk spillovers, and finally the order\u2019s corruption potential and the pathways a later administration could use to unwind the damage. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2025-21664.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"executive-summary",children:"Executive Summary"}),"\n",(0,n.jsxs)(t.p,{children:["Executive Order 14362, signed on November 24, 2025, did not itself designate any organization. What it actually did was more revealing: it created a fast-track interagency process directing the Secretary of State and the Secretary of the Treasury to produce a report within 30 days and then take action within 45 days regarding Muslim Brotherhood chapters, explicitly naming chapters in Lebanon, Jordan, and Egypt for consideration under the Foreign Terrorist Organization statute and the Specially Designated Global Terrorist sanctions framework. That structure matters. The order was framed as a neutral review, but its compressed timetable, named targets, and declared policy objective to \u201celiminate\u201d the capabilities and operations of designated chapters made clear that this was not a dispassionate fact-finding exercise. It was a presidential instruction to build an administrative record for a foreordained result. (",(0,n.jsx)(t.a,{href:"https://www.whitehouse.gov/presidential-actions/2025/11/designation-of-certain-muslim-brotherhood-chapters-as-foreign-terrorist-organizations-and-specially-designated-global-terrorists/",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["That result arrived quickly. On January 13, 2026, Treasury and State announced that the Egyptian and Jordanian branches of the Muslim Brotherhood were being designated as SDGTs under Executive Order 13224, while the Lebanese branch, al-Jamaa al-Islamiyah, was designated both as an FTO and an SDGT; State also designated its secretary general, Muhammad Fawzi Taqqosh, as an SDGT. The administration therefore used EO 14362 exactly as a launch platform for later sanctions and terrorism designations, not as an open-ended policy study. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2026-00573.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The administration\u2019s real target was not only violent actors. The broader political effect was to internationalize and intensify campaigns by authoritarian or semi-authoritarian regional partners against Islamist opposition currents, especially in Egypt and Jordan, and to widen the stigma radius around Muslim civic, charitable, and political activity more generally. Jordan had already moved in April 2025 to ban the Muslim Brotherhood after alleging an armed plot, threatening the space of its largest opposition ecosystem; Egypt had already spent years crushing the Brotherhood after the 2013 military overthrow of Mohamed Morsi. In that context, the U.S. move functioned less as a narrowly tailored counterterrorism action than as alignment with an anti-opposition regional order. (",(0,n.jsx)(t.a,{href:"https://apnews.com/article/02d78750d626506f3b989f9a241e6782?utm_source=openai",children:"apnews.com"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Formally, the order did not create new legal authority. It relied on existing authorities in section 219 of the INA, IEEPA, and Executive Order 13224. Functionally, however, it expanded executive power by converting authorities that are already highly deferential, secretive, and difficult to challenge into an instrument of presidential ideological direction. FTO designation triggers criminal liability for knowingly providing material support, visa inadmissibility, and blocking by U.S. financial institutions; judicial review is narrowly channeled to the D.C. Circuit and collateral attacks are barred in later criminal cases. Under EO 13224, State expressly relied on a no-prior-notice rationale because notice could enable instant asset transfers. That is exactly the kind of architecture that minimizes oversight while maximizing coercive leverage. (",(0,n.jsx)(t.a,{href:"https://www.justice.gov/archives/usam/criminal-resource-manual-16-providing-material-support-designated-terrorist-organizations",children:"justice.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The direct fiscal footprint of EO 14362 appears small and administratively absorbed, but that does not make its effects trivial. The order itself only specifies that publication costs are borne by the Department of State and that implementation is subject to appropriations. Treasury\u2019s Office of Terrorism and Financial Intelligence requested $237.662 million for FY 2026, with 659 direct FTE and a $10.8 million increase for national security programs, showing that the sanctions bureaucracy operating these tools is already heavily funded and expanding. The larger economic effects are externalized onto banks, charities, remittance channels, aid actors, dissidents, and diaspora communities through compliance overreach, de-risking, and political blacklisting. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2025-21664.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"what-the-order-formally-says-and-what-it-really-does",children:"What the Order Formally Says, and What It Really Does"}),"\n",(0,n.jsxs)(t.p,{children:["The order\u2019s formal text says it \u201csets in motion a process\u201d by which certain Muslim Brotherhood chapters \u201cshall be considered\u201d for designation as FTOs and SDGTs, and it cites alleged conduct by the Lebanese, Egyptian, and Jordanian chapters related to violence, incitement, or support for Hamas. Its policy section says the United States will work with regional partners to eliminate the capabilities and operations of any designated chapters and deprive them of resources. In legal form, then, EO 14362 is a process order: it commands interagency review, consultation, reporting, and subsequent action consistent with existing law. (",(0,n.jsx)(t.a,{href:"https://www.whitehouse.gov/presidential-actions/2025/11/designation-of-certain-muslim-brotherhood-chapters-as-foreign-terrorist-organizations-and-specially-designated-global-terrorists/",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["In practical operation, though, this was not just process. Naming specific chapters in the order itself, imposing a 30-day reporting deadline and a 45-day action deadline, and publicly describing the aim as resource deprivation and operational elimination converted \u201cconsideration\u201d into an executive conveyor belt. The White House fact sheet reinforced that reading by saying the order \u201cmandates\u201d State and Treasury to take action within 45 days after the report if appropriate and cast the move as one element of a broader counterterrorism and immigration crackdown that also included Houthi redesignation, cartel designations, and entry restrictions. The administration was not hiding the ball. It was using bureaucratic process as political cover for a policy decision already made. (",(0,n.jsx)(t.a,{href:"https://www.whitehouse.gov/fact-sheets/2025/11/fact-sheet-president-donald-j-trump-begins-process-to-designate-certain-muslim-brotherhood-chapters-as-foreign-terrorist-organizations-and-specially-designated-global-terrorists/",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["That distinction matters because the order\u2019s official framing presents the President as merely asking expert agencies to apply neutral criteria. But the statutory machinery is not actually insulated from presidential pressure. When the President names targets, sets the timeline, announces the policy outcome, and embeds the move in a larger narrative about foreign threats and internal enemies, the agencies are not operating in a neutral evidentiary space. They are being instructed to produce a legally defensible record for a desired result. That is a functional expansion of presidential control over tools that Congress formally vested in executive-branch officials but expected to be applied through law-bound determinations. (",(0,n.jsx)(t.a,{href:"https://www.whitehouse.gov/presidential-actions/2025/11/designation-of-certain-muslim-brotherhood-chapters-as-foreign-terrorist-organizations-and-specially-designated-global-terrorists/",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"how-the-order-was-implemented",children:"How the Order Was Implemented"}),"\n",(0,n.jsxs)(t.p,{children:["The implementation record confirms the real function of the order. On January 14, 2026, State published a notice designating the Lebanese Muslim Brotherhood, also known as al-Jamaa al-Islamiyah, as an FTO. On the same date, State published a separate EO 13224 notice designating both the Lebanese Muslim Brotherhood and Muhammad Fawzi Taqqosh as SDGTs. On January 15, 2026, OFAC published the SDGT designations of the Jordanian Muslim Brotherhood and the Egyptian Muslim Brotherhood, both linked by Treasury to Hamas. Treasury\u2019s January 13 press release explicitly said these actions were \u201cconsistent with\u201d EO 14362. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2026-00573.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["This matters because it shows the order was not symbolic. It generated concrete legal consequences. FTO designation brings three especially important effects: U.S. financial institutions must block funds in which the FTO or its agent has an interest, representatives and members are inadmissible and ineligible for visas, and knowingly providing material support to the FTO becomes a federal felony. Treasury\u2019s sanctions announcement added the classic EO 13224 consequences as well, including blocking of property and interests in property in the United States or in the possession or control of U.S. persons, and the \u201c50 percent rule\u201d for entities owned by blocked persons. (",(0,n.jsx)(t.a,{href:"https://www.justice.gov/osg/brief/rahmani-v-united-states-opposition",children:"justice.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The administration also chose an implementation model with very weak procedural safeguards. State\u2019s notice designating Taqqosh said prior notice was unnecessary because notice could allow instantaneous transfer of funds, a standard rationale under EO 13224. For FTO designations, review exists, but it is narrow: the designated organization has 30 days after Federal Register publication to seek review in the D.C. Circuit, and criminal defendants later prosecuted for material support cannot relitigate the validity of the designation as a defense. This is a structure built for speed and executive advantage, not for robust adversarial testing. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2026-00571.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"who-the-administration-is-trying-to-hurt",children:"Who the Administration Is Trying to Hurt"}),"\n",(0,n.jsxs)(t.p,{children:["The immediate targets were the named chapters in Lebanon, Jordan, and Egypt. But the administration was plainly trying to hurt a much wider field. It was trying to damage Islamist political opposition networks in allied states, especially where those networks challenge governments friendly to Washington. It was trying to make association with Brotherhood-linked political or charitable ecosystems more legally hazardous, more financially costly, and more reputationally toxic. It was trying to move Muslim civil society, diaspora funding, and pro-Palestinian advocacy closer to a zone of permanent suspicion. That is the real politics of this order. (",(0,n.jsx)(t.a,{href:"https://www.whitehouse.gov/presidential-actions/2025/11/designation-of-certain-muslim-brotherhood-chapters-as-foreign-terrorist-organizations-and-specially-designated-global-terrorists/",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The clearest beneficiaries were governments and factions already invested in crushing the Brotherhood as a political rival. Reuters noted that Egypt\u2019s Brotherhood won the country\u2019s first free presidential election in 2012 but was overthrown by the military in 2013 and then subjected to fierce repression. The Washington Post noted that Trump\u2019s first-term interest in a Brotherhood designation grew after meetings with Egyptian President Abdel Fattah el-Sisi, whose regime came to power through that coup. Jordan, meanwhile, had already banned the Brotherhood in April 2025 in a move that threatened the broader opposition sphere. The U.S. action therefore functioned as an external validator for domestic repression already underway. (",(0,n.jsx)(t.a,{href:"https://www.investing.com/news/world-news/us-designates-three-muslim-brotherhood-chapters-as-global-terrorists-4445321?utm_source=openai",children:"investing.com"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["There is also a domestic spillover target population. That does not mean EO 14362 itself designated U.S. Muslim organizations; it did not. But in broader-pattern context, Republican state officials in Texas and Florida moved in late 2025 to label CAIR and the Muslim Brotherhood as terrorist organizations, and CAIR sued, arguing those orders were unconstitutional and beyond state authority. Those state actions were not a direct legal implementation of EO 14362, but they were plainly nourished by the same political project: widening the category of people who can be stigmatized, disciplined, or silenced through terrorism rhetoric untethered from ordinary due process. (",(0,n.jsx)(t.a,{href:"https://apnews.com/article/e2fa10d1cd76f7a4a1ce98d4acda3ead?utm_source=openai",children:"apnews.com"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["So the answer to the user\u2019s question is stark. The administration is trying to hurt the named Brotherhood chapters, yes, but also Islamist opposition, Muslim civic infrastructure, dissidents in partner states, diaspora communities whose financial activity can be chilled by sanctions risk, and domestic Muslim advocates who can be smeared by association once the federal government normalizes this framing. That is not collateral damage. It is part of the point. (",(0,n.jsx)(t.a,{href:"https://home.treasury.gov/news/press-releases/sb0357",children:"home.treasury.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"legal-authority-constitutional-stakes-and-oversight",children:"Legal Authority, Constitutional Stakes, and Oversight"}),"\n",(0,n.jsxs)(t.p,{children:["The administration\u2019s legal hook is real. Section 219 of the INA authorizes FTO designation if the Secretary of State finds that the organization is foreign, engages in terrorist activity, and that its terrorism threatens U.S. nationals or U.S. national security. EO 13224, as amended, authorizes blocking of foreign persons who commit terrorism, pose significant risk of committing terrorism, or support designated terrorists, and leadership designations as well. EO 14362 therefore did not invent powers from nothing. It weaponized preexisting ones. (",(0,n.jsx)(t.a,{href:"https://www.justice.gov/osg/brief/rahmani-v-united-states-opposition",children:"justice.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["That is why the constitutional issue is not usually raw lack of authority. It is concentration, secrecy, and deference. Congress deliberately created a regime in which policymaking authority over terrorist designation is concentrated in the political branches and where later criminal defendants cannot attack the designation\u2019s validity. The D.C. Circuit has recognized some due-process constraints where a designated entity has significant U.S. presence, but the baseline structure remains heavily tilted toward executive discretion. In practical terms, that means a President can aim these tools at politically charged targets while facing only narrow judicial review and limited public visibility into the administrative record. (",(0,n.jsx)(t.a,{href:"https://www.justice.gov/osg/brief/rahmani-v-united-states-opposition",children:"justice.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["That is also why the order weakens oversight even though it does not amend a statute. The White House can claim it is merely directing lawful enforcement, while the real evidentiary basis, intelligence sourcing, and line-drawing decisions remain opaque. State\u2019s public notice for Taqqosh expressly invoked the no-prior-notice rationale. Treasury\u2019s press release asserted material support connections to Hamas and broader destabilization claims, but the public does not get the full record needed to test whether the government has cleanly separated violent conduct from political association, subgroup affiliation, or movement ideology. In a domain this coercive, that opacity is not a technical defect. It is the enabling condition. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2026-00571.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"durability-litigation-exposure-and-how-a-later-administration-could-reverse-it",children:"Durability, Litigation Exposure, and How a Later Administration Could Reverse It"}),"\n",(0,n.jsxs)(t.p,{children:["EO 14362 itself is politically durable only so long as the issuing President remains committed to it. Because it is a presidential directive rather than a statute, a later administration could revoke it quickly. But the downstream legal consequences are stickier. The actual FTO and SDGT designations were made through separate State and Treasury actions, so unwinding the order\u2019s effects would require more than symbolic repeal. A successor administration would need to revoke the EO, direct a fresh evidentiary review of the January 2026 designations, and then use State and Treasury authorities to revoke, narrow, or delist where the record does not justify continued designation. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2025-21664.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Litigation exposure is real but uneven. The Lebanese FTO designation is exposed to D.C. Circuit review under the statutory process. The SDGT designations are vulnerable to challenges arguing factual insufficiency, arbitrary treatment, mistaken attribution, or unlawful breadth, especially where designation theory blurs the line between a foreign political movement, a subgroup, and specific militant conduct. But the government starts with serious advantages: secret or classified records, institutional judicial deference, no-prior-notice rules in the sanctions context, and the criminal-law rule that the fact of designation, not its correctness, is what matters in a material-support prosecution. (",(0,n.jsx)(t.a,{href:"https://www.justice.gov/osg/brief/rahmani-v-united-states-opposition",children:"justice.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["A serious reversal program would therefore need to be structural, not merely rhetorical. A subsequent administration could restore discipline by requiring a written public statement of factual predicates for politically sensitive designations, strengthening internal separation between White House political staff and designation decisions, mandating publication of humanitarian guidance at the moment of designation, commissioning an inspector-general review of evidentiary quality and political interference, and seeking legislation that adds more meaningful congressional reporting and after-the-fact review. None of that is automatic. It would require a conscious decision to treat terrorism powers as powers that need containment, not as toys for political enemies lists. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2025-21664.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"implementation-feasibility-agency-capacity-and-procedural-requirements",children:"Implementation Feasibility, Agency Capacity, and Procedural Requirements"}),"\n",(0,n.jsxs)(t.p,{children:["From a narrow administrative standpoint, implementation was feasible, and the government proved it. The agencies met the order\u2019s timeline. State, Treasury, the Attorney General, and DNI were all embedded in the directed review structure, and the actual designations followed within weeks. The bureaucracy needed for sanctions designation already existed and was well resourced enough to execute. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2025-21664.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Treasury\u2019s own FY 2026 materials underscore that capacity. The Office of Terrorism and Financial Intelligence requested $237.662 million and 659 direct FTE for FY 2026, with a program increase of $10.8 million for national security programs, explicitly tied to disrupting terrorist operations and strengthening Treasury\u2019s intelligence infrastructure. That is not an ad hoc apparatus. It is an entrenched sanctions-and-financial-warfare machine with growing capability. (",(0,n.jsx)(t.a,{href:"https://home.treasury.gov/system/files/266/06.-TFI-FY-2026-CJ.pdf",children:"home.treasury.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The harder implementation problem is not whether the government can designate. It is whether it can calibrate downstream effects without indiscriminate overreach. On that question, the record is much weaker. When OFAC implemented the March 2025 Ansarallah FTO designation, it also updated and issued multiple general licenses and FAQs addressing humanitarian and commercial consequences. In the January 2026 Muslim Brotherhood actions, Treasury publicly emphasized blocking and sanctions implications, but the materials reviewed do not show a comparable chapter-specific humanitarian mitigation package. That asymmetry suggests an administration more focused on punitive signaling than on careful damage control. (",(0,n.jsx)(t.a,{href:"https://ofac.treasury.gov/faqs/1219",children:"ofac.treasury.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"fiscal-and-economic-effects",children:"Fiscal and Economic Effects"}),"\n",(0,n.jsxs)(t.p,{children:["The direct budgetary effect of EO 14362 is modest on paper. The order says publication costs are borne by the Department of State and implementation is subject to available appropriations. There is no publicly cited CBO-style score attached to the order. In that narrow sense, this is a low-cost executive action. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2025-21664.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["But the true economic effects are not borne inside the federal line item. They are displaced onto the private and nonprofit sectors through sanctions compliance, de-risking, frozen accounts, disrupted transactions, visa denials, criminal-law exposure, and heightened due-diligence costs. Treasury\u2019s January 2026 announcement made clear that U.S. persons are generally prohibited from transactions involving blocked property and that entities owned 50 percent or more by blocked persons are also blocked. For banks, platforms, charities, and remitters, that kind of regime predictably produces overcompliance. The result is often broader than the legal target. (",(0,n.jsx)(t.a,{href:"https://home.treasury.gov/news/press-releases/sb0357",children:"home.treasury.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The order\u2019s broader economic implications are therefore diffuse but serious. They likely include chilled remittances and donations, reduced access to banking or payment rails for groups perceived as adjacent to the designated networks, higher compliance and legal costs for NGOs operating in Egypt, Jordan, and Lebanon, and potential friction with partner states if local actors treated as mainstream political or social organizations are suddenly rendered radioactive in U.S.-linked finance. The administration did not publicly quantify those costs. That silence is itself revealing. This kind of action is designed to generate pain that is politically useful precisely because it is hard to see, hard to count, and easy to disclaim. (",(0,n.jsx)(t.a,{href:"https://home.treasury.gov/news/press-releases/sb0357",children:"home.treasury.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"downstream-developments-and-broader-governing-pattern",children:"Downstream Developments and Broader Governing Pattern"}),"\n",(0,n.jsxs)(t.p,{children:["The clearest direct linkage is the January 2026 designation package. EO 14362 was not the endpoint; it was the administrative runway. The Lebanese chapter was designated as both FTO and SDGT, the Egyptian and Jordanian branches were designated as SDGTs, and Taqqosh was separately designated. Treasury called those actions the first steps in an \u201congoing, sustained effort\u201d against Muslim Brotherhood violence and destabilization. That language points toward continuation, not closure. (",(0,n.jsx)(t.a,{href:"https://home.treasury.gov/news/press-releases/sb0357",children:"home.treasury.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The strongest plausible linkage beyond the four corners of the order is the attempt to use Brotherhood labeling as a wider political bludgeon. Senate and House Republicans pushed the Muslim Brotherhood Terrorist Designation Act of 2025, and Senator Cruz explicitly praised Trump\u2019s EO while urging Congress to \u201clock in\u201d the designations legislatively. That shows the order functioning as both operational policy and a staging ground for more durable statutory escalation. (",(0,n.jsx)(t.a,{href:"https://www.cruz.senate.gov/newsroom/in-the-news/sen-cruz-introduces-the-muslim-brotherhood-terrorist-designation-act?utm_source=openai",children:"cruz.senate.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The broader-pattern context is even more disturbing. EO 14362 sits inside an administration-wide strategy of stretching terrorism and national-security labels across migration, civil society, and ordinary governance. EO 14157 created a similar process for designating cartels and explicitly tied it to operational preparations for possible use of the Alien Enemies Act. The administration then invoked the Alien Enemies Act regarding Tren de Aragua and layered sweeping entry restrictions through later proclamations. Read together, these actions show a governing approach that treats extraordinary security authorities as normal tools for restructuring law enforcement, immigration, and political space. EO 14362 belongs to that pattern. It is not an isolated Middle East measure. It is part of a larger power project. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/01/29/2025-02004.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"harms-risks-and-second-order-effects",children:"Harms, Risks, and Second-Order Effects"}),"\n",(0,n.jsxs)(t.p,{children:["The most immediate harm is to democratic and civil space. In Jordan, where the Brotherhood had already been banned in April 2025, the U.S. move adds international stigma and financial coercion to a domestic crackdown that threatened the country\u2019s largest opposition ecosystem. In Egypt, where the Brotherhood had already been violently repressed after the 2013 coup, the designation helps retroactively bless a regime narrative that collapses political opposition into terrorism. In Lebanon, where al-Jamaa al-Islamiyah has political and social presence as well as an armed wing, the designation hardens a conflict frame and reduces room for separating armed conduct from broader communal or political networks. (",(0,n.jsx)(t.a,{href:"https://apnews.com/article/02d78750d626506f3b989f9a241e6782?utm_source=openai",children:"apnews.com"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["A second-order risk is that financial institutions and private intermediaries will not parse the legal nuances the way lawyers do. They will overcorrect. They will freeze first and ask later. They will sever accounts, terminate relationships, and avoid lawful but sensitive transactions. That kind of private overenforcement can spread far beyond the precise organizations named in the Federal Register. In practice, this means the burden will often land on people with the least capacity to contest it: migrants, donors, small charities, relatives sending money, and civil-society actors already under suspicion. (",(0,n.jsx)(t.a,{href:"https://home.treasury.gov/news/press-releases/sb0357",children:"home.treasury.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["A third risk is analytic corruption inside government. Once the White House turns a designation into a public loyalty test, intelligence and law-enforcement processes face pressure to produce confirming evidence rather than genuinely evaluate alternatives. That weakens the credibility of future designations, encourages guilt-by-affiliation theories, and invites future abuse against other disfavored ideological or religious networks. This is the real democratic danger of orders like EO 14362: not only the current target, but the lowering of the institutional threshold for who can be next. (",(0,n.jsx)(t.a,{href:"https://www.whitehouse.gov/presidential-actions/2025/11/designation-of-certain-muslim-brotherhood-chapters-as-foreign-terrorist-organizations-and-specially-designated-global-terrorists/",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"corruption-and-self-dealing-risk",children:"Corruption and Self-Dealing Risk"}),"\n",(0,n.jsxs)(t.p,{children:["There is no evidence in the sources reviewed that officials used EO 14362 for bribery, embezzlement, or personal enrichment. But the corruption opportunity is obvious and should be stated plainly. A designation regime of this kind creates leverage over sanctions listings, delisting reviews, licenses, evidentiary disclosures, access to officials, and reputational survival. A corrupt administration figure could use that leverage to solicit money, future employment for relatives, political endorsements, intelligence favors from foreign governments, or business for allied law firms, investigators, compliance vendors, and contractors. The ugliest version would be a protection-racket model: threaten a target with designation or maintain a weakly supported designation unless donors, intermediaries, or foreign patrons provide political support, financial favors, family jobs, or contracts to cronies. Another version would be selective enforcement, where politically useful allies receive quiet waivers or benign treatment while opponents are crushed. None of that is proven here, but the architecture is fertile ground for exactly that kind of abuse because it combines secrecy, discretion, foreign-policy exceptionalism, and immense coercive power. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2026-00571.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"final-assessment",children:"Final Assessment"}),"\n",(0,n.jsxs)(t.p,{children:["EO 14362 should be understood as a deliberately punitive executive instrument that used the language of review to stage a rapid designation campaign whose real significance lies beyond the formal text. It did not create new legal authority, but it did something politically dangerous: it showed how easily existing terrorism authorities can be bent into a project that aligns U.S. power with regional repression, narrows democratic space, increases executive discretion, weakens meaningful oversight, and spreads fear through financial and civic systems well beyond the named targets. The order\u2019s harms are not only the sanctions entries published in January 2026. The harms are the broader normalization of rule by stigma, secrecy, and ideological enemy-marking. That is why the order is not merely harsh. It is corrosive. And unless a later administration affirmatively revokes the order, reopens the underlying designations, restores procedural guardrails, and rebuilds a norm against politicized terrorism labeling, the damage will not stay confined to the Muslim Brotherhood. Tools used in bad faith do not remain specialized for long. They become the model. (",(0,n.jsx)(t.a,{href:"https://public-inspection.federalregister.gov/2025-21664.pdf",children:"public-inspection.federalregister.gov"}),")"]})]})}function h(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(c,{...e})}):c(e)}},28453:(e,t,i)=>{i.d(t,{R:()=>s,x:()=>o});var a=i(96540);const n={},r=a.createContext(n);function s(e){const t=a.useContext(r);return a.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:s(e.components),a.createElement(r.Provider,{value:t},e.children)}}}]);